import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val adj = Array(n.toInt()) { mutableListOf<List<Long>>() }
    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val s = edge[2]
        val e = edge[3]
        adj[u.toInt()].add(listOf(v, s, e))
    }

    val dist = Array(n.toInt()) { Long.MAX_VALUE }
    dist[0.toInt()] = 0L

    val pq = PriorityQueue<Pair<Long, Long>>()
    pq.add(Pair(0L, 0L))

    while (pq.isNotEmpty()) {
        val (current_time, u) = pq.poll()
        if (u == n - 1) return current_time
        for (edge in adj[u.toInt()]) {
            val v = edge[0]
            val s = edge[1]
            val e = edge[2]
            if (current_time <= e) {
                val earliest_take = max(current_time, s)
                val arrival_time = earliest_take + 1
                if (arrival_time < dist[v.toInt()]) {
                    dist[v.toInt()] = arrival_time
                    pq.add(Pair(arrival_time, v))
                }
            }
        }
    }

    return -1L
}
